import React, { useState, useEffect } from 'react';
import './CookieBanner.css';

export default function CookieBanner() {
  const [show, setShow] = useState(false);
  const [showManage, setShowManage] = useState(false);
  const [prefs, setPrefs] = useState({
    analytics: false,
    functional: false,
    marketing: false,
  });

  useEffect(() => {
    if (!localStorage.getItem('ame_cookie_consent')) {
      setTimeout(() => setShow(true), 600);
    }
  }, []);

  const close = (type, saved) => {
    localStorage.setItem(
      'ame_cookie_consent',
      JSON.stringify({ type, saved, date: new Date().toISOString() })
    );
    setShow(false);
  };

  const toggle = (key) =>
    setPrefs((p) => ({ ...p, [key]: !p[key] }));

  if (!show) return null;

  return (
    <div className="cb">
      <div className="cb__inner">

        {!showManage ? (
          <>
            <p className="cb__text">
              Utilizamos cookies para melhorar a experiência de navegação e identificar suas
              preferências. Você pode aceitar todos os cookies, rejeitar os não essenciais ou
              gerenciar os que serão usados. Leia mais em nossa{' '}
              <a href="/politica-de-privacidade" target="_blank" rel="noopener noreferrer">
                Política de Privacidade e cookies
              </a>.
            </p>

            <div className="cb__actions">
              <button
                className="cb__btn cb__btn--ghost"
                onClick={() => setShowManage(true)}
              >
                Gerenciar cookies
              </button>
              <button
                className="cb__btn cb__btn--outline"
                onClick={() => close('necessary', { analytics: false, functional: false, marketing: false })}
              >
                Rejeitar não essenciais
              </button>
              <button
                className="cb__btn cb__btn--primary"
                onClick={() => close('all', { analytics: true, functional: true, marketing: true })}
              >
                Aceitar todos
              </button>
            </div>
          </>
        ) : (
          <>
            <div className="cb__manage">
              <p className="cb__manage-title">Gerenciar preferências de cookies</p>
              <div className="cb__toggles">

                <div className="cb__row">
                  <div className="cb__row-info">
                    <span className="cb__row-label">Cookies essenciais</span>
                    <span className="cb__row-desc">Necessários para o funcionamento básico do site. Não podem ser desativados.</span>
                  </div>
                  <span className="cb__always">Sempre ativo</span>
                </div>

                {[
                  { key: 'analytics',  label: 'Cookies analíticos',   desc: 'Métricas de tráfego e comportamento (ex: Google Analytics).' },
                  { key: 'functional', label: 'Cookies funcionais',   desc: 'Funcionalidades aprimoradas como chat e formulários.' },
                  { key: 'marketing',  label: 'Cookies de marketing', desc: 'Anúncios personalizados e rastreamento de campanhas.' },
                ].map(({ key, label, desc }) => (
                  <div key={key} className="cb__row">
                    <div className="cb__row-info">
                      <span className="cb__row-label">{label}</span>
                      <span className="cb__row-desc">{desc}</span>
                    </div>
                    <button
                      className={`cb__switch ${prefs[key] ? 'cb__switch--on' : ''}`}
                      onClick={() => toggle(key)}
                      aria-pressed={prefs[key]}
                    >
                      <span className="cb__thumb" />
                    </button>
                  </div>
                ))}
              </div>
            </div>

            <div className="cb__actions">
              <button
                className="cb__btn cb__btn--ghost"
                onClick={() => setShowManage(false)}
              >
                ← Voltar
              </button>
              <button
                className="cb__btn cb__btn--outline"
                onClick={() => close('necessary', { analytics: false, functional: false, marketing: false })}
              >
                Rejeitar não essenciais
              </button>
              <button
                className="cb__btn cb__btn--outline"
                onClick={() => close('custom', prefs)}
              >
                Salvar seleção
              </button>
              <button
                className="cb__btn cb__btn--primary"
                onClick={() => close('all', { analytics: true, functional: true, marketing: true })}
              >
                Aceitar todos
              </button>
            </div>
          </>
        )}

      </div>
    </div>
  );
}
